#include <bits/stdc++.h>

std::vector<long long> minimum_closure_costs(int N, std::vector<int> U,std::vector<int> V,std::vector<int> W);

#define v first
#define w second
using namespace std;
typedef pair<int,int> pii;

const int N=5e5+10;

int n,d[N],p[N],fa[N];
long long f[N][2];
set<pii> e[N];
bool b[N];
int root[N],tot;
long long cnt,s[N];

struct Node{
    int s[2],f,sz;
    long long sum,val;
}a[N];

int New(long long val){
    tot++;
    a[tot].val=a[tot].sum=val,a[tot].sz=1;
    return tot;
}

void Update(int x){
    if(!x) return;
    a[x].sz=a[a[x].s[0]].sz+1+a[a[x].s[1]].sz;
    a[x].sum=a[a[x].s[0]].sum+a[x].val+a[a[x].s[1]].sum;
}

void Rotate(int x){
    int y=a[x].f,z=a[y].f,k=(a[y].s[1]==x);
    if(z) a[z].s[a[z].s[1]==y]=x;
    a[x].f=z;
    a[y].s[k]=a[x].s[k^1],a[a[x].s[k^1]].f=y;
    a[x].s[k^1]=y,a[y].f=x;
    Update(y),Update(x);
}

void Splay(int x,int p,int &root){
    while(a[x].f!=p){
        int y=a[x].f,z=a[y].f;
        if(z!=p)
            if((a[y].s[1]==x)^(a[z].s[1]==y)) Rotate(x);
            else Rotate(y);
        Rotate(x);
    }
    if(!p) root=x;
}

void Insert(int &root,long long val){
    if(!root){
        root=New(val);
        return;
    }
    int u=root,p;
    while(u){
        p=u;
        u=a[u].s[a[u].val<=val];
        a[p].sz++;
        a[p].sum+=val;
    }
    u=New(val);
    a[p].s[a[p].val<=val]=u,a[u].f=p;
    Splay(u,0,root);
}

void Remove(int &root,long long val){
    int u=root;
    while(a[u].val!=val)
        u=a[u].s[a[u].val<val];
    Splay(u,0,root);
    if(!a[u].s[1]){
        a[a[u].s[0]].f=0,root=a[u].s[0];
        return;
    }
    u=a[u].s[1];
    while(a[u].s[0])
        u=a[u].s[0];
    Splay(u,root,root);
    if(a[root].s[0]) a[a[root].s[0]].f=u;
    a[u].s[0]=a[root].s[0];
    a[u].f=0,root=u;
    Update(u);
}

void FindRank(int &root,int k){
    if(!root) return;
    int u=root;
    while(u){
        if(a[a[u].s[1]].sz+1==k) break;
        if(a[a[u].s[1]].sz>=k) u=a[u].s[1];
        else k-=a[a[u].s[1]].sz+1,u=a[u].s[0];
    }
    Splay(u,0,root);
}

void dfs2(int x,int k){
    b[x]=1;
    long long sum=0;
    for(auto y:e[x]){
        if(y.v==fa[x]) continue;
        dfs2(y.v,k);
        sum+=f[y.v][0];
        if(f[y.v][0]<f[y.v][1]+y.w)
            Insert(root[x],f[y.v][1]+y.w-f[y.v][0]);
    }
    if(!k) f[x][0]=sum;
    else{
        FindRank(root[x],min(k,a[root[x]].sz));
        f[x][0]=sum+a[root[x]].val+a[a[root[x]].s[1]].sum;
    }
    if(!k) f[x][1]=-1e18;
    else if(k==1) f[x][1]=sum;
    else{
        FindRank(root[x],min(k-1,a[root[x]].sz));
        f[x][1]=sum+a[root[x]].val+a[a[root[x]].s[1]].sum;
    }
    for(auto y:e[x]){
        if(y.v==fa[x]) continue;
        if(f[y.v][0]<f[y.v][1]+y.w)
            Remove(root[x],f[y.v][1]+y.w-f[y.v][0]);
    }
}

bool cmp(int x,int y){
    return d[x]<d[y];
}

void dfs(int x,int lst){
    fa[x]=lst;
    for(auto y:e[x])
        if(y.v!=lst)
            dfs(y.v,x);
}

int father(int x,int k){
    return d[fa[x]]>k?father(fa[x],k):x;
}

void Erase(int x){
    b[x]=1;
    for(auto y:e[x])
        if(!b[y.v]){
            Insert(root[y.v],y.w);
            e[y.v].erase(make_pair(x,y.w));
            s[y.v]+=y.w;
        }
    cnt+=s[x];
}

vector<long long> minimum_closure_costs(int N, std::vector<int> U,std::vector<int> V,std::vector<int> W){
    n=N;
    long long sum=0;
    for(int i=0;i<n-1;i++){
        int u=U[i]+1,v=V[i]+1,w=W[i];
        e[u].insert(make_pair(v,w));
        e[v].insert(make_pair(u,w));
        sum+=w;
    }
    for(int i=1;i<=n;i++)
        d[i]=e[i].size(),p[i]=i;
    sort(p+1,p+n+1,cmp);
    dfs(1,0);
    vector<long long> res;
    for(int i=0,j=1;i<n;i++){
        while(j<=n && d[p[j]]<=i){
            Erase(p[j]);
            j++;
        }
        long long ans=sum-cnt;
        for(int k=j;k<=n;k++){
            if(!b[p[k]]){
                int rt=father(p[k],i);
                dfs2(rt,i);
                ans-=f[rt][0];
            }
        }
        for(int k=j;k<=n;k++)
            b[p[k]]=0;
        res.push_back(ans);
    }
    return res;
}
